import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Brain, Sparkles, Calculator, Heart, Zap, ArrowRight, ArrowLeft, 
  Activity, Gauge, Play, Pause, RotateCw, Settings, Volume2, Send, 
  Bug, AlertCircle, BarChart3, TrendingUp, Download, Eye
} from 'lucide-react';

const CognitiveFeedbackEngine = () => {
  // === CORE STATE: Three Minds with Internal Balances ===
  const [orchestrator, setOrchestrator] = useState({
    alpha: 0.65,
    emotions: {
      curious: 0.7,
      impatient: 0.3,
      insightful: 0.5,
      patient: 0.6
    },
    currentThought: "",
    decision: null
  });

  const [creative, setCreative] = useState({
    alpha: 0.85,
    virtues: {
      confidence: 0.8,
      momentum: 0.6,
      wildness: 0.9,
      coherence: 0.5
    },
    currentThought: "",
    lastFeedback: null
  });

  const [analytical, setAnalytical] = useState({
    alpha: 0.35,
    virtues: {
      skepticism: 0.75,
      precision: 0.85,
      openness: 0.3,
      rigor: 0.9
    },
    currentThought: "",
    lastFeedback: null
  });

  // === BENJAMIN FRANKLIN VIRTUE ENGINE ===
  const [globalVirtues, setGlobalVirtues] = useState({
    temperance: 0.7,
    industry: 0.5,
    resolution: 0.8,
    humility: 0.3,
    tranquility: 0.6,
    sincerity: 0.7,
    justice: 0.6
  });

  // === CONVERSATION & PROCESSING STATE ===
  const [userInput, setUserInput] = useState("");
  const [conversation, setConversation] = useState([]);
  const [emergentThought, setEmergentThought] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentTurn, setCurrentTurn] = useState(0);

  // === USER CONTROLS ===
  const [showControls, setShowControls] = useState(false);
  const [controls, setControls] = useState({
    maxTurns: 10,
    tokenMin: 120,
    tokenMax: 200,
    commitmentThreshold: 0.80,  // How committed needed to deeply defend ideas
    engagementSensitivity: 0.7,  // Multiplier for how quickly commitment builds
    synthesisThreshold: 0.70  // Convergence score needed for synthesis
  });

  // === INTELLECTUAL COMMITMENT STATE (persistent across turns) ===
  const [intellectualState, setIntellectualState] = useState({
    creative: {
      commitment: 0.25,  // Baseline intellectual engagement
      momentum: 0,       // Recent idea development velocity
      lastEngagement: null
    },
    analytical: {
      commitment: 0.25,
      momentum: 0,
      lastEngagement: null
    }
  });

  // === DEBUG STATE ===
  const [debugLogs, setDebugLogs] = useState([]);
  const [showDebug, setShowDebug] = useState(false);
  const [lastError, setLastError] = useState(null);

  // === ANALYTICS STATE ===
  const [showAnalytics, setShowAnalytics] = useState(false);
  const [analyticsData, setAnalyticsData] = useState({
    alphaHistory: {
      orchestrator: [],
      creative: [],
      analytical: []
    },
    emotionHistory: {
      curious: [],
      impatient: [],
      insightful: [],
      patient: []
    },
    virtueHistory: {
      creative: {
        confidence: [],
        momentum: [],
        wildness: [],
        coherence: []
      },
      analytical: {
        skepticism: [],
        precision: [],
        openness: [],
        rigor: []
      }
    },
    feedbackEvents: [],
    stateTransitions: [],
    globalVirtueHistory: {
      temperance: [],
      industry: [],
      resolution: [],
      humility: [],
      tranquility: [],
      sincerity: [],
      justice: []
    }
  });

  // === FEEDBACK LOOP TRACKING ===
  const [feedbackLoops, setFeedbackLoops] = useState([]);

  // === INTELLECTUAL COMMITMENT CALCULATION (Lock-in Dynamics) ===
  const calculateCommitment = (text, systemState, previousCommitment = 0.25) => {
    if (!text) return previousCommitment;

    let commitmentScore = previousCommitment; // Start from current state

    // Engagement markers (signs of deep thinking, not anger)
    const engagementMarkers = {
      conviction: ['must', 'cannot', 'fundamental', 'critical', 'essential', 'crucial'],
      insight: ['realize', 'understand', 'see', 'reveals', 'shows', 'demonstrates'],
      defense: ['because', 'specifically', 'the key is', 'what matters', 'the point'],
      deepening: ['actually', 'in fact', 'the real', 'more precisely', 'to be clear'],
      building: ['furthermore', 'moreover', 'additionally', 'also consider', 'and']
    };

    // Count engagement markers
    let engagementBonus = 0;
    Object.entries(engagementMarkers).forEach(([category, markers]) => {
      markers.forEach(marker => {
        try {
          const regex = new RegExp(marker, 'gi');
          const count = (text.match(regex) || []).length;
          engagementBonus += count * 0.08;
        } catch (e) {
          console.warn(`Error processing marker "${marker}":`, e);
        }
      });
    });

    // Length indicates sustained thinking
    if (text.length > 250) {
      engagementBonus += 0.15;
    }

    // Apply engagement with sensitivity
    commitmentScore += engagementBonus * controls.engagementSensitivity;

    // LOCK-IN PHASE TRANSITION (Sigmoid curve from PDF page 13)
    // 0.0-0.5: Slow growth (exploration)
    // 0.5-0.7: Rapid growth (momentum building)
    // 0.7+: Locked in (deep commitment)

    if (commitmentScore >= 0.5 && commitmentScore < 0.7) {
      // Acceleration zone - ideas gaining momentum
      commitmentScore += 0.12;
    }

    if (commitmentScore >= 0.7 && commitmentScore < 0.85) {
      // Deep commitment zone - idea feels important
      commitmentScore += 0.08;
    }

    if (commitmentScore >= 0.85) {
      // Locked in - approaching asymptote at 0.95
      commitmentScore = Math.min(0.95, commitmentScore + 0.03);
    }

    // Decay only works below threshold (hysteresis)
    if (commitmentScore < 0.7 && engagementBonus < 0.1) {
      commitmentScore -= 0.08; // Can cool off in exploration phase
    }

    return Math.max(0.20, Math.min(0.95, commitmentScore));
  };

  // === ENGAGEMENT ANALYSIS (replaces critique severity) ===
  const analyzeEngagement = (text) => {
    const analysis = {
      depth: 0,        // How deeply they're thinking
      specificity: 0,  // Concrete vs vague
      building: false, // Building on previous ideas
      challenging: false // Challenging assumptions (productive)
    };

    // Depth markers
    const deepWords = ['because', 'mechanism', 'specifically', 'precisely', 'exactly', 'demonstrates'];
    const shallowWords = ['maybe', 'perhaps', 'possibly', 'could be', 'might'];

    deepWords.forEach(word => {
      if (text.toLowerCase().includes(word)) analysis.depth += 0.2;
    });
    shallowWords.forEach(word => {
      if (text.toLowerCase().includes(word)) analysis.depth -= 0.1;
    });

    // Specificity
    const specificMarkers = ['for example', 'specifically', 'the mechanism is', 'this works by'];
    specificMarkers.forEach(marker => {
      if (text.toLowerCase().includes(marker)) analysis.specificity += 0.25;
    });

    // Building on ideas
    if (text.includes('your point about') || text.includes('building on')) {
      analysis.building = true;
    }

    // Productive challenge
    if (text.includes('but') || text.includes('however') || text.includes('yet')) {
      analysis.challenging = true;
    }

    analysis.depth = Math.max(0, Math.min(1, analysis.depth));
    analysis.specificity = Math.max(0, Math.min(1, analysis.specificity));

    return analysis;
  };

  // === INTELLECTUAL MOMENTUM TRACKING ===
  const [momentumHistory, setMomentumHistory] = useState({
    creative: { recentEngagements: [], avgDepth: 0 },
    analytical: { recentEngagements: [], avgDepth: 0 }
  });

  const trackMomentum = (system, engagement) => {
    setMomentumHistory(prev => {
      const history = prev[system].recentEngagements;
      const updated = [...history, engagement].slice(-3); // Keep last 3
      const avgDepth = updated.reduce((sum, e) => sum + e.depth, 0) / updated.length;

      return {
        ...prev,
        [system]: {
          recentEngagements: updated,
          avgDepth: avgDepth
        }
      };
    });
  };

  const getMomentumBonus = (system) => {
    const history = momentumHistory[system];
    if (history.recentEngagements.length < 2) return 0;

    // If sustained deep engagement, momentum increases
    if (history.avgDepth > 0.6) {
      return 0.15; // Building momentum bonus
    }

    return 0;
  };

  // === DYNAMIC SYNTHESIS DETECTION (Truth-Seeking Focus) ===
  const shouldSynthesize = (conversationHistory) => {
    try {
      if (!conversationHistory || conversationHistory.length < 4) return false;
      if (currentTurn >= controls.maxTurns) return true;

      const recentTurns = conversationHistory.slice(-4);
      let convergenceScore = 0;

      // Meta-commentary detection (reflecting on the dialogue itself)
      const metaPhrases = ['this dialogue', 'our discussion', 'the tension', 'both perspectives', 'synthesis', 'neither alone', 'reveals that', 'shows that'];
      recentTurns.forEach(turn => {
        if (turn && turn.text) {
          metaPhrases.forEach(phrase => {
            if (turn.text.toLowerCase().includes(phrase)) convergenceScore += 0.20;
          });
        }
      });

      // Deep exploration exhausted (covered different angles thoroughly)
      const lastCreative = recentTurns.filter(t => t && t.mode === 'creative').slice(-2);
      const lastAnalytical = recentTurns.filter(t => t && t.mode === 'analytical').slice(-2);

      if (lastCreative.length === 2 && lastAnalytical.length === 2) {
        const creativeOverlap = calculateTextSimilarity(lastCreative[0].text, lastCreative[1].text);
        const analyticalOverlap = calculateTextSimilarity(lastAnalytical[0].text, lastAnalytical[1].text);

        if (creativeOverlap > 0.3 || analyticalOverlap > 0.3) {
          convergenceScore += 0.25; // Repeating similar ideas = explored fully
        }
      }

      // Both systems deeply committed (high commitment → needs synthesis)
      const highCommitmentCount = recentTurns.filter(t => 
        t && t.commitment && t.commitment > 0.75
      ).length;

      if (highCommitmentCount >= 3) {
        convergenceScore += 0.30; // Deep commitment from both = synthesis ready
      }

      // Agreement or integration markers
      const integrationPhrases = ['you\'re right', 'fair point', 'valid', 'that\'s true', 'I see', 'makes sense', 'both', 'together'];
      recentTurns.forEach(turn => {
        if (turn && turn.text) {
          integrationPhrases.forEach(phrase => {
            if (turn.text.toLowerCase().includes(phrase)) convergenceScore += 0.15;
          });
        }
      });

      return convergenceScore >= controls.synthesisThreshold;
    } catch (e) {
      console.error('Error in shouldSynthesize:', e);
      return false;
    }
  };

  const calculateTextSimilarity = (text1, text2) => {
    // Simple word overlap similarity
    const words1 = text1.toLowerCase().split(/\s+/).filter(w => w.length > 4);
    const words2 = text2.toLowerCase().split(/\s+/).filter(w => w.length > 4);

    const common = words1.filter(w => words2.includes(w)).length;
    const total = Math.max(words1.length, words2.length);

    return total > 0 ? common / total : 0;
  };

  // === ANALYTICS LOGGING ===
  const logAnalytics = useCallback((type, data) => {
    const timestamp = Date.now();

    setAnalyticsData(prev => {
      const updated = { ...prev };

      switch(type) {
        case 'alpha':
          updated.alphaHistory = {
            orchestrator: [...prev.alphaHistory.orchestrator, { time: timestamp, value: data.orchestrator }],
            creative: [...prev.alphaHistory.creative, { time: timestamp, value: data.creative }],
            analytical: [...prev.alphaHistory.analytical, { time: timestamp, value: data.analytical }]
          };
          break;

        case 'emotions':
          Object.keys(data).forEach(emotion => {
            updated.emotionHistory[emotion] = [
              ...(prev.emotionHistory[emotion] || []),
              { time: timestamp, value: data[emotion] }
            ];
          });
          break;

        case 'virtues':
          if (data.system === 'creative') {
            Object.keys(data.values).forEach(virtue => {
              updated.virtueHistory.creative[virtue] = [
                ...(prev.virtueHistory.creative[virtue] || []),
                { time: timestamp, value: data.values[virtue] }
              ];
            });
          } else if (data.system === 'analytical') {
            Object.keys(data.values).forEach(virtue => {
              updated.virtueHistory.analytical[virtue] = [
                ...(prev.virtueHistory.analytical[virtue] || []),
                { time: timestamp, value: data.values[virtue] }
              ];
            });
          }
          break;

        case 'feedback':
          updated.feedbackEvents = [
            ...prev.feedbackEvents,
            { time: timestamp, ...data }
          ];
          break;

        case 'transition':
          updated.stateTransitions = [
            ...prev.stateTransitions,
            { time: timestamp, ...data }
          ];
          break;

        case 'globalVirtues':
          Object.keys(data).forEach(virtue => {
            updated.globalVirtueHistory[virtue] = [
              ...(prev.globalVirtueHistory[virtue] || []),
              { time: timestamp, value: data[virtue] }
            ];
          });
          break;
      }

      return updated;
    });
  }, []);

  // === DEBUG LOGGING HELPER ===
  const addDebugLog = (type, message, data = null) => {
    const log = {
      timestamp: new Date().toISOString(),
      type,
      message,
      data
    };
    console.log(`[${type.toUpperCase()}]`, message, data || '');
    setDebugLogs(prev => [...prev, log].slice(-20));
  };

  // === IMPROVED JSON EXTRACTION ===
  const extractJSON = (text) => {
    addDebugLog('info', 'Attempting JSON extraction from response', { rawLength: text.length });

    try {
      const parsed = JSON.parse(text);
      addDebugLog('success', 'Direct JSON parse succeeded');
      return parsed;
    } catch (e) {
      addDebugLog('warning', 'Direct parse failed, trying extraction', { error: e.message });
    }

    const jsonPattern = /\{[\s\S]*"nextMode"[\s\S]*\}/;
    const match = text.match(jsonPattern);

    if (match) {
      try {
        const parsed = JSON.parse(match[0]);
        addDebugLog('success', 'Regex extraction succeeded');
        return parsed;
      } catch (e) {
        addDebugLog('error', 'Regex extraction found JSON but parse failed', { error: e.message });
      }
    }

    const lines = text.split('\n');
    let jsonStart = -1;
    let jsonEnd = -1;

    for (let i = 0; i < lines.length; i++) {
      if (lines[i].includes('{') && jsonStart === -1) {
        jsonStart = i;
      }
      if (lines[i].includes('}') && jsonStart !== -1) {
        jsonEnd = i;
        break;
      }
    }

    if (jsonStart !== -1 && jsonEnd !== -1) {
      const jsonText = lines.slice(jsonStart, jsonEnd + 1).join('\n');
      try {
        const parsed = JSON.parse(jsonText);
        addDebugLog('success', 'Line-by-line extraction succeeded');
        return parsed;
      } catch (e) {
        addDebugLog('error', 'Line-by-line extraction failed', { error: e.message });
      }
    }

    addDebugLog('error', 'All JSON extraction methods failed', { rawText: text.substring(0, 200) });
    return null;
  };

  // === CLAUDE API INTEGRATION WITH LOGGING ===
  const callClaude = async (messages, model = "claude-sonnet-4-20250514", maxTokens = 600, context = "unknown") => {
    addDebugLog('info', `Calling Claude API (${context})`, { model, maxTokens });

    try {
      const response = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          model: model,
          max_tokens: maxTokens,
          messages: messages
        })
      });

      if (!response.ok) {
        const errorText = await response.text();
        addDebugLog('error', `API request failed (${context})`, { 
          status: response.status, 
          error: errorText.substring(0, 200) 
        });
        setLastError(`API Error: ${response.status}`);
        return null;
      }

      const data = await response.json();

      if (data.content && data.content[0] && data.content[0].text) {
        let text = data.content[0].text;

        addDebugLog('success', `API call succeeded (${context})`, { 
          responseLength: text.length,
          preview: text.substring(0, 150) + '...'
        });

        text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

        return text;
      }

      addDebugLog('error', `Invalid response format (${context})`, { data });
      throw new Error("Invalid response format");

    } catch (error) {
      addDebugLog('error', `Claude API error (${context})`, { error: error.message });
      setLastError(error.message);
      console.error("Claude API error:", error);
      return null;
    }
  };

  // === ORCHESTRATOR LOGIC FOR TRUTH-SEEKING DIALOGUE ===
  const callOrchestrator = async (prompt, conversationSoFar, lastSystemCommitment = 0) => {
    addDebugLog('info', 'Orchestrator guiding dialogue', { turn: currentTurn, lastCommitment: lastSystemCommitment });

    const emotionalContext = `
    Current state:
    - Curiosity: ${(orchestrator.emotions.curious * 100).toFixed(0)}%
    - Impatience: ${(orchestrator.emotions.impatient * 100).toFixed(0)}%
    - Insightfulness: ${(orchestrator.emotions.insightful * 100).toFixed(0)}%
    - Patience: ${(orchestrator.emotions.patient * 100).toFixed(0)}%

    Internal balance (alpha): ${orchestrator.alpha.toFixed(2)}
    ${orchestrator.alpha > 0.7 ? "I'm encouraging exploratory thinking" : 
      orchestrator.alpha < 0.4 ? "I'm seeking structured analysis" : 
      "I'm balancing exploration and rigor"}

    ${lastSystemCommitment > controls.commitmentThreshold ? 
      `NOTE: Previous system showed deep commitment (${(lastSystemCommitment * 100).toFixed(0)}%). They may need space to fully develop their insight.` : ''}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude acting as a DIALOGUE ORCHESTRATOR guiding truth-seeking conversation between creative and analytical thinking modes.

      ${emotionalContext}

      Your role is to GUIDE productive intellectual exploration, while allowing deeply committed ideas to be fully developed.

      Your emotional state influences your guidance:
      - High curiosity → encourage deeper exploration
      - High impatience → push toward synthesis
      - High insightfulness → recognize when ready for breakthrough

      Original question: "${prompt}"

      Recent dialogue:
      ${conversationSoFar || "Beginning exploration"}

      IMPORTANT: Give SPECIFIC intellectual challenges, not generic prompts.
      Guide them to engage directly with each other's ideas.

      CRITICAL: Respond ONLY with valid JSON. No extra text.

      {
        "nextMode": "creative" or "analytical" or "synthesis",
        "instruction": "Specific intellectual challenge or direction",
        "tokenLimit": ${controls.tokenMin}-${controls.tokenMax},
        "reasoning": "Why this direction serves truth-seeking",
        "emotionalShift": {
          "curious": 0.1 or -0.1 or 0,
          "impatient": 0.1 or -0.1 or 0,
          "insightful": 0.1 or -0.1 or 0
        }
      }

      Good instructions focus on ideas:
      - "Defend the experiential validity of your position"
      - "Identify the specific logical gap in their reasoning"
      - "Show how both positions reveal something true"

      Bad instructions are generic:
      - "Continue the dialogue"
      - "Respond to the previous point"`
    }];

    const response = await callClaude(messages, "claude-sonnet-4-20250514", 300, "orchestrator");

    if (response) {
      addDebugLog('info', 'Processing orchestrator guidance');

      const decision = extractJSON(response);

      if (decision && decision.nextMode) {
        addDebugLog('success', 'Orchestrator decision parsed', decision);

        logAnalytics('transition', {
          from: 'orchestrator',
          decision: decision.nextMode,
          reasoning: decision.reasoning,
          allowsDeepEngagement: lastSystemCommitment > controls.commitmentThreshold
        });

        if (decision.emotionalShift) {
          const newEmotions = {
            curious: Math.max(0, Math.min(1, orchestrator.emotions.curious + (decision.emotionalShift.curious || 0))),
            impatient: Math.max(0, Math.min(1, orchestrator.emotions.impatient + (decision.emotionalShift.impatient || 0))),
            insightful: Math.max(0, Math.min(1, orchestrator.emotions.insightful + (decision.emotionalShift.insightful || 0))),
            patient: orchestrator.emotions.patient
          };

          setOrchestrator(prev => ({
            ...prev,
            emotions: newEmotions
          }));

          logAnalytics('emotions', newEmotions);
        }

        return decision;
      } else {
        addDebugLog('warning', 'Failed to parse decision, using fallback');
        setLastError('Orchestrator returned unparseable response');

        return {
          nextMode: currentTurn % 2 === 0 ? "creative" : "analytical",
          instruction: "Continue developing your perspective on this question",
          tokenLimit: controls.tokenMax,
          reasoning: `Fallback decision (turn ${currentTurn}): ${currentTurn % 2 === 0 ? 'Creative exploration' : 'Analytical examination'}`,
          emotionalShift: {
            curious: 0,
            impatient: 0.05,
            insightful: 0
          }
        };
      }
    }

    addDebugLog('error', 'Orchestrator call failed completely');
    return null;
  };

  // === CREATIVE MODE FOR DEEP EXPLORATION ===
  const callCreativeMode = async (prompt, instruction, conversationContext, tokenLimit, deeplyCommitted = false) => {
    const creativeContext = `
    Your internal creative state:
    - Confidence: ${(creative.virtues.confidence * 100).toFixed(0)}%
    - Momentum: ${(creative.virtues.momentum * 100).toFixed(0)}%
    - Wildness: ${(creative.virtues.wildness * 100).toFixed(0)}%
    - Coherence: ${(creative.virtues.coherence * 100).toFixed(0)}%

    Creative alpha: ${creative.alpha.toFixed(2)}
    ${creative.alpha > 0.8 ? "You're in expansive, exploratory thinking" :
      creative.alpha > 0.6 ? "You're in creative flow" :
      "You're balancing creativity with rigor"}

    ${deeplyCommitted ? `
    You're deeply committed to this line of thinking. If you feel this idea deserves fuller development,
    you may exceed the token limit to properly articulate your insight.` : ''}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude in CREATIVE MODE - intuitive, exploratory, possibility-focused thinking.

      ${creativeContext}

      Let your internal state guide your thinking:
      - High wildness → explore unconventional connections
      - Low confidence → acknowledge uncertainty while pursuing ideas
      - High momentum → build on previous insights

      This is a cognitive mode, not a separate identity. You remain Claude.

      Original question: "${prompt}"

      Recent dialogue:
      ${conversationContext || "Starting exploration"}

      Guidance: "${instruction}"

      CRITICAL: DIRECTLY ENGAGE with the analytical perspective's last point.
      This is collaborative truth-seeking - respond to their specific concerns or build on valid points.

      Token guideline: ~${tokenLimit} tokens (can exceed if deeply committed to developing an important insight)

      Think out loud, explore connections, propose possibilities - this is about discovering truth together.`
    }];

    return await callClaude(messages, "claude-sonnet-4-20250514", tokenLimit + 100, "creative");
  };

  // === ANALYTICAL MODE FOR RIGOROUS EXAMINATION ===
  const callAnalyticalMode = async (prompt, instruction, conversationContext, tokenLimit, deeplyCommitted = false) => {
    const analyticalContext = `
    Your internal analytical state:
    - Skepticism: ${(analytical.virtues.skepticism * 100).toFixed(0)}%
    - Precision: ${(analytical.virtues.precision * 100).toFixed(0)}%
    - Openness: ${(analytical.virtues.openness * 100).toFixed(0)}%
    - Rigor: ${(analytical.virtues.rigor * 100).toFixed(0)}%

    Analytical alpha: ${analytical.alpha.toFixed(2)}
    ${analytical.alpha < 0.3 ? "You're in rigorous examination mode" :
      analytical.alpha < 0.5 ? "You're balancing rigor with openness" :
      "You're open to unconventional ideas while maintaining logical standards"}

    ${deeplyCommitted ? `
    You're deeply committed to rigorous analysis. If you need more space to properly examine
    logical structure, you may exceed the token limit to ensure thoroughness.` : ''}
    `;

    const messages = [{
      role: "user",
      content: `You are Claude in ANALYTICAL MODE - logical, systematic, precision-focused thinking.

      ${analyticalContext}

      Let your internal state guide your analysis:
      - High skepticism → probe assumptions carefully
      - High precision → demand clear definitions
      - High openness → consider unconventional possibilities
      - High rigor → maintain logical standards

      This is a cognitive mode, not a separate identity. You remain Claude.

      Original question: "${prompt}"

      Recent dialogue:
      ${conversationContext || "Starting examination"}

      Guidance: "${instruction}"

      CRITICAL: DIRECTLY EXAMINE the creative perspective's last point.
      Identify specific strengths and weaknesses - this is collaborative truth-seeking, not dismissal.

      Token guideline: ~${tokenLimit} tokens (can exceed if thorough analysis requires it)

      Be rigorous but fair - point out logical gaps AND acknowledge valid insights. Seek truth together.`
    }];

    return await callClaude(messages, "claude-sonnet-4-20250514", tokenLimit + 100, "analytical");
  };

  // === FEEDBACK IMPACT WITH INTELLECTUAL INFLUENCE ===
  const calculateFeedbackImpact = (senderType, receiverType, message) => {
    const impact = {
      alphaShift: 0,
      virtueShifts: {},
      emotionShifts: {}
    };

    const engagement = analyzeEngagement(message);

    // Track momentum for both systems
    if (senderType === 'creative' || senderType === 'analytical') {
      trackMomentum(senderType, engagement);
    }

    // Creative → Analytical feedback (exploratory ideas influencing rigor)
    if (senderType === 'creative' && receiverType === 'analytical') {
      if (engagement.depth > 0.6) {
        // Deep creative thinking makes analytical more open
        impact.virtueShifts.openness = 0.10;
        impact.alphaShift = 0.05; // Slightly more open to exploration
      }

      if (engagement.building) {
        // Building on ideas increases analytical confidence in the direction
        impact.virtueShifts.precision = 0.05;
      }
    }

    // Analytical → Creative feedback (rigorous examination influencing exploration)
    if (senderType === 'analytical' && receiverType === 'creative') {
      if (engagement.challenging && engagement.specificity > 0.5) {
        // Specific challenges make creative more careful
        impact.virtueShifts.coherence = 0.15;
        impact.virtueShifts.wildness = -0.05; // Slightly more constrained
      }

      if (engagement.depth > 0.7) {
        // Deep analysis can inspire confidence if ideas hold up
        impact.virtueShifts.confidence = 0.10;
      } else if (engagement.depth > 0.4) {
        // Moderate challenge requires more careful articulation
        impact.virtueShifts.momentum = -0.05;
      }
    }

    // Both → Orchestrator feedback (ideas influencing meta-cognition)
    if (receiverType === 'orchestrator') {
      if (message.length > 250) {
        impact.emotionShifts.impatient = 0.08; // Long responses need guidance
      }

      if (engagement.depth > 0.7) {
        impact.emotionShifts.curious = 0.15; // Deep thinking is interesting
        impact.emotionShifts.insightful = 0.12;
      }

      // Meta-commentary increases insightfulness
      if (message.includes('reveals') || message.includes('shows that') || message.includes('both')) {
        impact.emotionShifts.insightful = 0.20;
      }
    }

    // Log feedback event with engagement context
    logAnalytics('feedback', {
      sender: senderType,
      receiver: receiverType,
      impact: impact,
      engagement: engagement,
      messageLength: message.length
    });

    return impact;
  };

  // === APPLY FEEDBACK WITH ANALYTICS ===
  const applyFeedback = (systemName, impact) => {
    switch(systemName) {
      case 'orchestrator':
        setOrchestrator(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newEmotions = { ...prev.emotions };

          Object.keys(impact.emotionShifts || {}).forEach(emotion => {
            newEmotions[emotion] = Math.max(0, Math.min(1, 
              newEmotions[emotion] + impact.emotionShifts[emotion]
            ));
          });

          // Log changes
          logAnalytics('alpha', {
            orchestrator: newAlpha,
            creative: creative.alpha,
            analytical: analytical.alpha
          });
          logAnalytics('emotions', newEmotions);

          return { ...prev, alpha: newAlpha, emotions: newEmotions };
        });
        break;

      case 'creative':
        setCreative(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newVirtues = { ...prev.virtues };

          Object.keys(impact.virtueShifts || {}).forEach(virtue => {
            newVirtues[virtue] = Math.max(0, Math.min(1, 
              newVirtues[virtue] + impact.virtueShifts[virtue]
            ));
          });

          // Log changes
          logAnalytics('alpha', {
            orchestrator: orchestrator.alpha,
            creative: newAlpha,
            analytical: analytical.alpha
          });
          logAnalytics('virtues', { system: 'creative', values: newVirtues });

          return { ...prev, alpha: newAlpha, virtues: newVirtues };
        });
        break;

      case 'analytical':
        setAnalytical(prev => {
          const newAlpha = Math.max(0, Math.min(1, prev.alpha + (impact.alphaShift || 0)));
          const newVirtues = { ...prev.virtues };

          Object.keys(impact.virtueShifts || {}).forEach(virtue => {
            newVirtues[virtue] = Math.max(0, Math.min(1, 
              newVirtues[virtue] + impact.virtueShifts[virtue]
            ));
          });

          // Log changes
          logAnalytics('alpha', {
            orchestrator: orchestrator.alpha,
            creative: creative.alpha,
            analytical: newAlpha
          });
          logAnalytics('virtues', { system: 'analytical', values: newVirtues });

          return { ...prev, alpha: newAlpha, virtues: newVirtues };
        });
        break;
    }
  };

  // === MAIN THINKING PROCESS WITH INTELLECTUAL MOMENTUM ===
  const processThought = async () => {
    if (!userInput || isProcessing) return;

    setIsProcessing(true);
    setConversation([]);
    setCurrentTurn(0);
    setFeedbackLoops([]);
    setEmergentThought("");
    setDebugLogs([]);
    setLastError(null);

    // Reset intellectual state to baseline
    setIntellectualState({
      creative: { commitment: 0.25, momentum: 0, lastEngagement: null },
      analytical: { commitment: 0.25, momentum: 0, lastEngagement: null }
    });

    // Reset momentum history
    setMomentumHistory({
      creative: { recentEngagements: [], avgDepth: 0 },
      analytical: { recentEngagements: [], avgDepth: 0 }
    });

    // Reset analytics
    setAnalyticsData({
      alphaHistory: { orchestrator: [], creative: [], analytical: [] },
      emotionHistory: { curious: [], impatient: [], insightful: [], patient: [] },
      virtueHistory: {
        creative: { confidence: [], momentum: [], wildness: [], coherence: [] },
        analytical: { skepticism: [], precision: [], openness: [], rigor: [] }
      },
      feedbackEvents: [],
      stateTransitions: [],
      globalVirtueHistory: {
        temperance: [], industry: [], resolution: [], humility: [],
        tranquility: [], sincerity: [], justice: []
      }
    });

    addDebugLog('info', 'Starting thought processing', { input: userInput });

    // Log initial state
    logAnalytics('alpha', {
      orchestrator: orchestrator.alpha,
      creative: creative.alpha,
      analytical: analytical.alpha
    });
    logAnalytics('emotions', orchestrator.emotions);
    logAnalytics('virtues', { system: 'creative', values: creative.virtues });
    logAnalytics('virtues', { system: 'analytical', values: analytical.virtues });

    let localConversation = [];
    let turn = 0;
    let lastSystemCommitment = 0;

    while (turn < controls.maxTurns) {
      addDebugLog('info', `Starting turn ${turn + 1}/${controls.maxTurns}`);

      // Check for synthesis readiness
      if (shouldSynthesize(localConversation)) {
        addDebugLog('info', 'Synthesis triggered - ideas explored sufficiently');
        break;
      }

      const conversationContext = localConversation
        .slice(-4)
        .map(t => `${t.mode.toUpperCase()}: ${t.text}`)
        .join('\n\n');

      setOrchestrator(prev => ({ ...prev, currentThought: "Guiding exploration..." }));

      const decision = await callOrchestrator(userInput, conversationContext, lastSystemCommitment);
      if (!decision) {
        addDebugLog('error', 'Orchestrator failed, stopping process');
        break;
      }

      const orchestratorTurn = {
        mode: 'orchestrator',
        text: `${decision.reasoning} → Next: ${decision.nextMode}`,
        alpha: orchestrator.alpha,
        decision: decision
      };

      localConversation.push(orchestratorTurn);
      setConversation(prev => [...prev, orchestratorTurn]);
      setOrchestrator(prev => ({ 
        ...prev, 
        currentThought: decision.reasoning,
        decision: decision
      }));

      if (decision.nextMode === 'synthesis' || shouldSynthesize(localConversation)) {
        addDebugLog('info', 'Synthesis mode triggered');

        const synthesis = await callClaude([{
          role: "user",
          content: `Based on this dialogue between creative and analytical thinking, synthesize the emergent insight:

          ${conversationContext}

          Provide a brief synthesis that captures truth from both perspectives.`
        }], "claude-sonnet-4-20250514", 150, "synthesis");

        setEmergentThought(synthesis || "Truth emerges from the tension between exploration and rigor.");
        break;
      }

      let modeResponse = "";
      let modeTurn = {};
      let systemCommitment = 0;

      try {
        if (decision.nextMode === 'creative') {
          setCreative(prev => ({ ...prev, currentThought: "Exploring possibilities..." }));

          // Get current commitment state
          const currentCommitment = intellectualState.creative.commitment;
          const deeplyCommitted = currentCommitment >= controls.commitmentThreshold;

          modeResponse = await callCreativeMode(
            userInput, 
            decision.instruction, 
            conversationContext,
            decision.tokenLimit || controls.tokenMax,
            deeplyCommitted
          );

          if (modeResponse) {
            // Calculate new commitment with lock-in dynamics
            systemCommitment = calculateCommitment(modeResponse, 'creative', currentCommitment);

            // Apply momentum bonus
            const momentumBonus = getMomentumBonus('creative');
            systemCommitment = Math.min(0.95, systemCommitment + momentumBonus);

            // Update persistent state
            setIntellectualState(prev => ({
              ...prev,
              creative: {
                commitment: systemCommitment,
                momentum: momentumBonus,
                lastEngagement: analyzeEngagement(modeResponse)
              }
            }));

            modeTurn = {
              mode: 'creative',
              text: modeResponse,
              alpha: creative.alpha,
              commitment: systemCommitment,
              deepEngagement: deeplyCommitted && modeResponse.length > decision.tokenLimit
            };

            setCreative(prev => ({ ...prev, currentThought: modeResponse }));

            const impact = calculateFeedbackImpact('creative', 'analytical', modeResponse);
            applyFeedback('analytical', impact);

            addDebugLog('info', `Creative mode completed (commitment: ${(systemCommitment * 100).toFixed(0)}%)`);

            const commitmentLevel = systemCommitment >= 0.85 ? "deeply committed" :
                                   systemCommitment >= 0.70 ? "strongly engaged" :
                                   systemCommitment >= 0.50 ? "building momentum" :
                                   "exploring";

            setFeedbackLoops(prev => [...prev, {
              from: 'creative',
              to: 'analytical',
              message: `${commitmentLevel} - needs rigorous examination`,
              commitment: systemCommitment
            }]);
          }

        } else if (decision.nextMode === 'analytical') {
          setAnalytical(prev => ({ ...prev, currentThought: "Examining rigorously..." }));

          const currentCommitment = intellectualState.analytical.commitment;
          const deeplyCommitted = currentCommitment >= controls.commitmentThreshold;

          modeResponse = await callAnalyticalMode(
            userInput, 
            decision.instruction, 
            conversationContext,
            decision.tokenLimit || controls.tokenMax,
            deeplyCommitted
          );

          if (modeResponse) {
            systemCommitment = calculateCommitment(modeResponse, 'analytical', currentCommitment);

            const momentumBonus = getMomentumBonus('analytical');
            systemCommitment = Math.min(0.95, systemCommitment + momentumBonus);

            setIntellectualState(prev => ({
              ...prev,
              analytical: {
                commitment: systemCommitment,
                momentum: momentumBonus,
                lastEngagement: analyzeEngagement(modeResponse)
              }
            }));

            modeTurn = {
              mode: 'analytical',
              text: modeResponse,
              alpha: analytical.alpha,
              commitment: systemCommitment,
              deepEngagement: deeplyCommitted && modeResponse.length > decision.tokenLimit
            };

            setAnalytical(prev => ({ ...prev, currentThought: modeResponse }));

            const impact = calculateFeedbackImpact('analytical', 'creative', modeResponse);
            applyFeedback('creative', impact);

            addDebugLog('info', `Analytical mode completed (commitment: ${(systemCommitment * 100).toFixed(0)}%)`);

            const commitmentLevel = systemCommitment >= 0.85 ? "deeply committed" :
                                   systemCommitment >= 0.70 ? "strongly engaged" :
                                   systemCommitment >= 0.50 ? "building rigor" :
                                   "examining";

            setFeedbackLoops(prev => [...prev, {
              from: 'analytical',
              to: 'creative',
              message: `${commitmentLevel} - demands careful response`,
              commitment: systemCommitment
            }]);
          }
        }
      } catch (error) {
        addDebugLog('error', `Mode execution failed: ${error.message}`);
        console.error('Mode execution error:', error);
      }

      if (modeResponse) {
        localConversation.push(modeTurn);
        setConversation(prev => [...prev, modeTurn]);

        const orchestratorImpact = calculateFeedbackImpact(
          modeTurn.mode, 
          'orchestrator', 
          modeResponse
        );
        applyFeedback('orchestrator', orchestratorImpact);

        lastSystemCommitment = systemCommitment;
      }

      // Update global virtues
      const newGlobalVirtues = {
        temperance: (orchestrator.alpha + creative.alpha + analytical.alpha) / 3,
        industry: globalVirtues.industry,
        resolution: Math.max(globalVirtues.resolution, orchestrator.emotions.insightful),
        humility: Math.min(1, globalVirtues.humility + (analytical.virtues.skepticism - creative.virtues.confidence) * 0.05),
        tranquility: 1 - orchestrator.emotions.impatient,
        sincerity: globalVirtues.sincerity,
        justice: globalVirtues.justice
      };

      setGlobalVirtues(newGlobalVirtues);
      logAnalytics('globalVirtues', newGlobalVirtues);

      turn++;
      setCurrentTurn(turn);

      await new Promise(resolve => setTimeout(resolve, 800));
    }

    if (!emergentThought && localConversation.length > 2) {
      addDebugLog('info', 'Generating synthesis from exploration');

      const finalContext = localConversation
        .filter(t => t.mode !== 'orchestrator')
        .slice(-4)
        .map(t => `${t.mode.toUpperCase()}: ${t.text}`)
        .join('\n\n');

      const synthesis = await callClaude([{
        role: "user",
        content: `Synthesize this intellectual exploration into a single emergent insight:
        ${finalContext}`
      }], "claude-sonnet-4-20250514", 150, "final-synthesis");

      setEmergentThought(synthesis || "The exploration continues...");
    }

    addDebugLog('success', 'Thought processing complete');
    setIsProcessing(false);
  };

  // === EXPORT ANALYTICS DATA ===
  const exportAnalytics = () => {
    try {
      // Check if there's data to export
      if (!analyticsData || Object.keys(analyticsData).length === 0) {
        alert('No analytics data to export yet. Run a thought process first!');
        return;
      }

      // Create a safe copy without circular references
      const safeData = {
        alphaHistory: analyticsData.alphaHistory,
        emotionHistory: analyticsData.emotionHistory,
        virtueHistory: analyticsData.virtueHistory,
        feedbackEvents: analyticsData.feedbackEvents.map(e => ({
          time: e.time,
          sender: e.sender,
          receiver: e.receiver,
          impact: e.impact,
          messageLength: e.messageLength
        })),
        stateTransitions: analyticsData.stateTransitions,
        globalVirtueHistory: analyticsData.globalVirtueHistory,
        metadata: {
          exportTime: new Date().toISOString(),
          totalEvents: analyticsData.feedbackEvents.length,
          totalTransitions: analyticsData.stateTransitions.length
        }
      };

      const dataStr = JSON.stringify(safeData, null, 2);
      const dataBlob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(dataBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `cognitive-analytics-${Date.now()}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

      console.log('Analytics exported successfully');
    } catch (error) {
      console.error('Export failed:', error);
      alert(`Export failed: ${error.message}. Check console for details.`);
    }
  };

  // === UI COMPONENTS ===

