                <div className="flex justify-between text-white/50 mb-1">
                  <span>{event.sender} → {event.receiver}</span>
                  <span>{new Date(event.time).toLocaleTimeString()}</span>
                </div>
                {event.impact.alphaShift !== 0 && (
                  <div className="text-purple-300">
                    α shift: {event.impact.alphaShift > 0 ? '+' : ''}{event.impact.alphaShift.toFixed(3)}
                  </div>
                )}
                {Object.keys(event.impact.virtueShifts || {}).length > 0 && (
                  <div className="text-blue-300 text-xs">
                    {Object.entries(event.impact.virtueShifts).map(([k, v]) => 
                      `${k}: ${v > 0 ? '+' : ''}${v.toFixed(2)}`
                    ).join(', ')}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* State Transitions */}
        <div>
          <h4 className="text-white/70 text-sm font-semibold mb-2">
            State Transitions ({analyticsData.stateTransitions.length})
          </h4>
          <div className="space-y-1 max-h-40 overflow-y-auto">
            {analyticsData.stateTransitions.slice(-5).reverse().map((trans, idx) => (
              <div key={idx} className="bg-white/5 rounded p-2 text-xs">
                <div className="flex justify-between text-white/50 mb-1">
                  <span className="font-semibold text-white/70">{trans.decision}</span>
                  <span>{new Date(trans.time).toLocaleTimeString()}</span>
                </div>
                <div className="text-white/60 text-xs italic line-clamp-2">
                  {trans.reasoning}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  // Debug Panel Component (keeping existing)
  const DebugPanel = () => {
    if (!showDebug) return null;

    return (
      <div className="fixed right-4 top-4 w-96 bg-black/90 backdrop-blur-md rounded-xl p-4 border border-red-500/50 max-h-96 overflow-y-auto z-50">
        <div className="flex items-center justify-between mb-3">
          <div className="flex items-center">
            <Bug className="w-5 h-5 text-red-400 mr-2" />
            <h3 className="text-white font-bold">Debug Console</h3>
          </div>
          <button 
            onClick={() => setShowDebug(false)}
            className="text-white/50 hover:text-white"
          >
            ×
          </button>
        </div>

        {lastError && (
          <div className="bg-red-500/20 border border-red-500/50 rounded p-2 mb-3">
            <div className="flex items-start">
              <AlertCircle className="w-4 h-4 text-red-400 mr-2 mt-0.5" />
              <p className="text-red-300 text-xs">{lastError}</p>
            </div>
          </div>
        )}

        <div className="space-y-2">
          {debugLogs.map((log, idx) => (
            <div 
              key={idx}
              className={`text-xs p-2 rounded ${
                log.type === 'error' ? 'bg-red-500/20 text-red-300' :
                log.type === 'warning' ? 'bg-yellow-500/20 text-yellow-300' :
                log.type === 'success' ? 'bg-green-500/20 text-green-300' :
                'bg-blue-500/20 text-blue-300'
              }`}
            >
              <div className="font-mono text-white/50 text-xs mb-1">
                {new Date(log.timestamp).toLocaleTimeString()}
              </div>
              <div className="font-semibold mb-1">{log.message}</div>
              {log.data && (
                <pre className="text-xs overflow-x-auto mt-1 opacity-70">
                  {typeof log.data === 'object' 
                    ? JSON.stringify(log.data, null, 2).substring(0, 200) + '...'
                    : String(log.data).substring(0, 200) + '...'
                  }
                </pre>
              )}
            </div>
          ))}
        </div>
      </div>
    );
  };

  // System Card Component (keeping existing implementation)
  const SystemCard = ({ title, icon: Icon, system, color, position }) => {
    const getEmotionEmoji = (key) => {
      const emojis = {
        curious: '🤔', impatient: '😤', insightful: '💡', patient: '⏳',
        confident: '💪', wild: '🌪️', skeptical: '🤨', precise: '🎯',
        confidence: '💪', momentum: '🏃', wildness: '🌪️', coherence: '🎯',
        skepticism: '🤨', precision: '📐', openness: '🌈', rigor: '⚖️'
      };
      return emojis[key] || '🧠';
    };

    const getColorClass = (color) => {
      const colors = {
        purple: 'bg-purple-500',
        blue: 'bg-blue-500',
        pink: 'bg-pink-500'
      };
      return colors[color] || 'bg-gray-500';
    };

    return (
      <div className={`bg-white/10 backdrop-blur-md rounded-2xl p-6 ${
        position === 'top' ? 'w-96' : 'w-80'
      } border border-white/20 transform transition-all duration-300 hover:scale-105`}>
        <div className="flex items-center mb-4">
          <div className={`w-12 h-12 ${getColorClass(color)} rounded-full flex items-center justify-center`}>
            <Icon className="w-6 h-6 text-white" />
          </div>
          <div className="ml-3">
            <h2 className="text-white font-bold">{title}</h2>
            <p className="text-purple-200 text-sm">
              {position === 'top' ? 'The Shepherd' : `System ${position === 'left' ? '1' : '2'}`}
            </p>
          </div>
        </div>

        <div className="mb-4">
          <div className="flex justify-between text-xs text-purple-200 mb-1">
            <span>{position === 'left' ? 'Restrained' : position === 'right' ? 'Rigid' : 'Control'}</span>
            <span className="font-mono">α = {system.alpha.toFixed(2)}</span>
            <span>{position === 'left' ? 'Wild' : position === 'right' ? 'Open' : 'Flow'}</span>
          </div>
          <div className="h-3 bg-black/30 rounded-full relative">
            <div 
              className="absolute top-1/2 -translate-y-1/2 w-5 h-5 bg-white rounded-full shadow-lg border-2 border-purple-400 transition-all duration-500"
              style={{ left: `${system.alpha * 100}%` }}
            />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2 mb-4">
          {Object.entries(system.emotions || system.virtues).slice(0, 4).map(([key, value]) => (
            <div key={key} className="bg-black/30 rounded-lg p-2">
              <div className="flex items-center justify-between">
                <span className="text-xs text-white/70 capitalize">{key}</span>
                <span className="text-lg">{getEmotionEmoji(key)}</span>
              </div>
              <div className="h-1 bg-gray-600 rounded-full mt-1">
                <div 
                  className={`h-full ${getColorClass(color)} rounded-full transition-all duration-300`}
                  style={{ width: `${value * 100}%` }}
                />
              </div>
            </div>
          ))}
        </div>

        <div className="bg-purple-500/20 rounded-lg p-3 border border-purple-400/30">
          <p className="text-xs text-white/70 mb-1">Current Thought:</p>
          <p className="text-white text-sm italic line-clamp-3">
            {system.currentThought || "Waiting..."}
          </p>
        </div>
      </div>
    );
  };

  // Benjamin Franklin Virtues Display (keeping existing)
  const VirtueEngine = () => {
    return (
      <div className="bg-white/5 backdrop-blur-md rounded-2xl p-6 border border-white/10">
        <h3 className="text-white font-bold mb-4 text-center">
          Benjamin Franklin Virtue Engine
        </h3>
        <div className="grid grid-cols-7 gap-3">
          {Object.entries(globalVirtues).map(([virtue, level]) => (
            <div key={virtue} className="text-center">
              <p className="text-xs text-white/70 mb-2 capitalize">{virtue}</p>
              <div className="h-20 w-8 mx-auto bg-black/30 rounded-full relative overflow-hidden">
                <div 
                  className="absolute bottom-0 w-full bg-gradient-to-t from-purple-500 to-purple-300 rounded-full transition-all duration-500"
                  style={{ height: `${level * 100}%` }}
                />
              </div>
              <p className="text-xs text-white/50 mt-1">{(level * 100).toFixed(0)}%</p>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 to-purple-900 p-8">
      <DebugPanel />
      <AnalyticsPanel />
      <ControlPanel />

      <div className="text-center mb-8">
        <div className="flex items-center justify-center mb-2 gap-4">
          <h1 className="text-3xl font-bold text-white">
            Cognitive Feedback Engine
          </h1>
          <button
            onClick={() => setShowControls(!showControls)}
            className="bg-purple-500/20 hover:bg-purple-500/30 text-purple-300 px-3 py-1 rounded-lg text-sm flex items-center transition-all"
          >
            <Settings className="w-4 h-4 mr-1" />
            Controls
          </button>
          <button
            onClick={() => setShowAnalytics(!showAnalytics)}
            className="bg-purple-500/20 hover:bg-purple-500/30 text-purple-300 px-3 py-1 rounded-lg text-sm flex items-center transition-all"
          >
            <Eye className="w-4 h-4 mr-1" />
            Analytics
          </button>
          <button
            onClick={() => setShowDebug(!showDebug)}
            className="bg-red-500/20 hover:bg-red-500/30 text-red-300 px-3 py-1 rounded-lg text-sm flex items-center transition-all"
          >
            <Bug className="w-4 h-4 mr-1" />
            Debug
          </button>
        </div>
        <p className="text-purple-200">Dynamic Cognitive Combat with Passion Overrides</p>
      </div>

      <div className="max-w-7xl mx-auto">
        <div className="mb-8 flex justify-center">
          <div className="bg-white/10 backdrop-blur-md rounded-xl p-4 w-full max-w-2xl">
            <div className="flex gap-2">
              <input
                type="text"
                value={userInput}
                onChange={(e) => setUserInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && processThought()}
                placeholder="Enter a thought to process..."
                className="flex-1 bg-black/30 text-white rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-purple-500"
                disabled={isProcessing}
              />
              <button
                onClick={processThought}
                disabled={isProcessing || !userInput}
                className="bg-gradient-to-r from-purple-500 to-blue-500 text-white px-6 py-2 rounded-lg font-semibold disabled:opacity-50 transition-all hover:scale-105"
              >
                {isProcessing ? (
                  <div className="flex items-center">
                    <Brain className="w-5 h-5 mr-2 animate-pulse" />
                    Processing...
                  </div>
                ) : (
                  <div className="flex items-center">
                    <Play className="w-5 h-5 mr-2" />
                    Think
                  </div>
                )}
              </button>
            </div>
            {isProcessing && (
              <div className="mt-2 text-xs text-purple-300 text-center">
                Turn {currentTurn} of {controls.maxTurns} • Synthesis at {(controls.synthesisThreshold * 100).toFixed(0)}%
              </div>
            )}
          </div>
        </div>

        <div className="space-y-8">
          <div className="flex justify-center">
            <SystemCard
              title="ORCHESTRATOR"
              icon={Brain}
              system={orchestrator}
              color="purple"
              position="top"
            />
          </div>

          {feedbackLoops.length > 0 && (
            <div className="flex justify-center">
              <div className="relative w-96 h-12">
                <svg className="w-full h-full">
                  <path
                    d="M 50 10 Q 200 30 350 10"
                    stroke="#8b5cf6"
                    strokeWidth="2"
                    fill="none"
                    className="animate-pulse"
                  />
                  <path
                    d="M 350 40 Q 200 20 50 40"
                    stroke="#3b82f6"
                    strokeWidth="2"
                    fill="none"
                    className="animate-pulse"
                    style={{ animationDelay: '0.5s' }}
                  />
                </svg>
              </div>
            </div>
          )}

          <div className="flex justify-center gap-8">
            <SystemCard
              title="CREATIVE MODE"
              icon={Sparkles}
              system={creative}
              color="purple"
              position="left"
            />
            <SystemCard
              title="ANALYTICAL MODE"
              icon={Calculator}
              system={analytical}
              color="blue"
              position="right"
            />
          </div>
        </div>

        <div className="mt-8">
          <VirtueEngine />
        </div>

        {emergentThought && (
          <div className="mt-8">
            <div className="bg-gradient-to-r from-purple-500/20 to-blue-500/20 rounded-2xl p-6 backdrop-blur-md border border-white/20">
              <h3 className="text-white font-bold mb-4 text-center">
                Emergent Synthesis
              </h3>
              <p className="text-white/90 italic text-center text-lg">
                "{emergentThought}"
              </p>
              <div className="mt-4 flex justify-center gap-4">
                <span className="text-sm text-purple-300">
                  Creative: {(creative.alpha * 100).toFixed(0)}%
                </span>
                <span className="text-sm text-white/50">|</span>
                <span className="text-sm text-blue-300">
                  Analytical: {(analytical.alpha * 100).toFixed(0)}%
                </span>
                <span className="text-sm text-white/50">|</span>
                <span className="text-sm text-green-300">
                  Coherence: {((orchestrator.emotions.insightful + globalVirtues.resolution) * 50).toFixed(0)}%
                </span>
              </div>
            </div>
          </div>
        )}

        {conversation.length > 0 && (
          <div className="mt-8 bg-black/30 rounded-xl p-4">
            <h3 className="text-white font-bold mb-3">Thought Stream</h3>
            <div className="space-y-2 max-h-96 overflow-y-auto">
              {conversation.map((turn, idx) => (
                <div 
                  key={idx}
                  className={`p-3 rounded-lg bg-gradient-to-r ${
                    turn.mode === 'orchestrator' ? 'from-purple-500/20 to-purple-600/20' :
                    turn.mode === 'creative' ? 'from-pink-500/20 to-purple-500/20' :
                    'from-blue-500/20 to-cyan-500/20'
                  }`}
                >
                  <div className="flex items-center justify-between mb-1">
                    <div className="flex items-center gap-2">
                      <span className="text-white/70 text-sm font-semibold capitalize">
                        {turn.mode}
                      </span>
                      {turn.passion !== undefined && turn.passion !== null && (
                        <span className={`text-xs px-2 py-0.5 rounded ${
                          turn.passion > 0.7 ? 'bg-red-500/30 text-red-300' :
                          turn.passion > 0.5 ? 'bg-orange-500/30 text-orange-300' :
                          'bg-green-500/30 text-green-300'
                        }`}>
                          🔥 {(turn.passion * 100).toFixed(0)}%
                        </span>
                      )}
                      {turn.overrode && (
                        <span className="text-xs bg-yellow-500/30 text-yellow-300 px-2 py-0.5 rounded">
                          ⚡ Override
                        </span>
                      )}
                    </div>
                    <span className="text-white/50 text-xs font-mono">
                      α={turn.alpha.toFixed(2)}
                    </span>
                  </div>
                  <p className="text-white/90 text-sm">{turn.text}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {feedbackLoops.length > 0 && (
          <div className="mt-4 bg-black/20 rounded-lg p-3">
            <h4 className="text-white/70 text-xs font-semibold mb-2">Feedback Loops</h4>
            <div className="flex flex-wrap gap-2">
              {feedbackLoops.slice(-5).map((loop, idx) => (
                <span 
                  key={idx} 
                  className={`text-xs rounded px-2 py-1 ${
                    loop.passion && loop.passion > 0.7 ? 'bg-red-500/20 text-red-300' :
                    loop.passion && loop.passion > 0.5 ? 'bg-orange-500/20 text-orange-300' :
                    'bg-white/10 text-white/60'
                  }`}
                >
                  {loop.from} → {loop.to}: "{loop.message}"
                  {loop.passion !== undefined && loop.passion !== null && ` 🔥${(loop.passion * 100).toFixed(0)}%`}
                </span>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default CognitiveFeedbackEngine;
